import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { Plus, X, Tag, Palette, Edit2 } from 'lucide-react';
import ModalFeedback from '../components/ModalFeedback';
import '../styles/Categorias.css';

const Categorias = () => {
  const [categorias, setCategorias] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('despesa');
  const [showModal, setShowModal] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [selectedId, setSelectedId] = useState(null);
  
  const [form, setForm] = useState({ nome: '', cor: '#4361ee' });

  useEffect(() => {
    buscarCategorias();
  }, []);

  async function buscarCategorias() {
    setLoading(true);
    const { data } = await supabase.from('categorias').select('*').order('nome');
    setCategorias(data || []);
    setLoading(false);
  }

  const openModal = (cat = null) => {
    if (cat) {
      setEditMode(true);
      setSelectedId(cat.id);
      setForm({ nome: cat.nome, cor: cat.cor });
    } else {
      setEditMode(false);
      setForm({ nome: '', cor: '#4361ee' });
    }
    setShowModal(true);
  };

  async function handleSalvar(e) {
    e.preventDefault();
    const { data: { user } } = await supabase.auth.getUser();

    const payload = { 
      user_id: user.id, 
      nome: form.nome, 
      tipo: activeTab, 
      cor: form.cor 
    };

    if (editMode) {
      await supabase.from('categorias').update(payload).eq('id', selectedId);
    } else {
      await supabase.from('categorias').insert([payload]);
    }

    setShowModal(false);
    buscarCategorias();
  }

  async function excluirCategoria() {
    if (window.confirm(`Excluir a categoria "${form.nome}"?`)) {
      await supabase.from('categorias').delete().eq('id', selectedId);
      setShowModal(false);
      buscarCategorias();
    }
  }

  const categoriasFiltradas = categorias.filter(c => c.tipo === activeTab);

  return (
    <div className="cat-page-wrapper fade-in">
      <header className="cat-header">
        <div className="cat-title-area">
          <h1>Categorias</h1>
          <p>Gerencie seus rótulos de {activeTab}s</p>
        </div>
        
        <div className="cat-tab-container">
          <button 
            className={activeTab === 'provento' ? 'active' : ''} 
            onClick={() => setActiveTab('provento')}
          >
            Entradas
          </button>
          <button 
            className={activeTab === 'despesa' ? 'active' : ''} 
            onClick={() => setActiveTab('despesa')}
          >
            Saídas
          </button>
        </div>
      </header>

      <div className="cat-list-container">
        {loading ? (
          <div className="cat-status">Carregando...</div>
        ) : categoriasFiltradas.length > 0 ? (
          categoriasFiltradas.map(cat => (
            <div key={cat.id} className="cat-item-row" onClick={() => openModal(cat)}>
              <div className="cat-item-main">
                <div className="cat-status-dot" style={{ backgroundColor: cat.cor }}></div>
                <span className="cat-item-name" style={{ color: cat.cor }}>
                  {cat.nome}
                </span>
              </div>
              <Edit2 size={16} className="cat-edit-icon" />
            </div>
          ))
        ) : (
          <div className="cat-empty">Nenhuma categoria encontrada.</div>
        )}
      </div>

      <button className="cat-fab" onClick={() => openModal()}>
        <Plus size={24} />
      </button>

      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="cat-modal fade-in" onClick={e => e.stopPropagation()}>
            <div className="cat-modal-header">
              <h3>{editMode ? 'Editar Categoria' : 'Nova Categoria'}</h3>
              <button onClick={() => setShowModal(false)}><X size={20}/></button>
            </div>

            <form onSubmit={handleSalvar} className="cat-modal-form">
              <div className="cat-input-box">
                <label><Tag size={14}/> Nome</label>
                <input 
                  type="text" required value={form.nome} 
                  onChange={e => setForm({...form, nome: e.target.value})} 
                  placeholder="Ex: Lazer, Aluguel..."
                />
              </div>
              
              <div className="cat-input-box">
                <label><Palette size={14}/> Cor Personalizada</label>
                <div className="cat-color-wrapper">
                   <input 
                    type="color" value={form.cor} 
                    onChange={e => setForm({...form, cor: e.target.value})} 
                  />
                  <span>{form.cor.toUpperCase()}</span>
                </div>
              </div>

              <div className="cat-modal-actions">
                {editMode && (
                  <button type="button" className="btn-cat-delete" onClick={excluirCategoria}>
                    Excluir
                  </button>
                )}
                <button type="submit" className="btn-cat-save">
                  {editMode ? 'Salvar Alterações' : 'Criar Categoria'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Categorias;
